code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Card, Chip, icon } from 'decantr/components';

code.example:
function ResourceGaugeGrid({ resources }) {
  const { div, span, h2, h3 } = tags;
  const usageColor = pct => pct > 90 ? '_bgerror' : pct > 70 ? '_bgwarning' : pct > 50 ? '_bgprimary' : '_bgsuccess';
  const usageLabel = pct => pct > 90 ? 'Critical' : pct > 70 ? 'High' : pct > 50 ? 'Moderate' : 'Healthy';
  const usageVariant = pct => pct > 90 ? 'error' : pct > 70 ? 'warning' : pct > 50 ? 'default' : 'success';

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _aic _jcsb') },
      h2({ class: css('_heading4') }, 'Resource Usage'),
      Badge({ variant: 'default' }, `${resources.length} resources`)
    ),
    div({ class: css('_grid _gcaf280 _gap4') },
      ...resources.map(r => {
        const pct = Math.round((r.used / r.max) * 100);
        return Card({},
          Card.Body({ class: css('_flex _col _gap3 _p4') },
            div({ class: css('_flex _aic _jcsb') },
              div({ class: css('_flex _aic _gap2') },
                icon(r.icon, { size: '1em', class: css('_fgprimary') }),
                h3({ class: css('_textsm _bold') }, r.name)
              ),
              Chip({ label: usageLabel(pct), size: 'xs', variant: usageVariant(pct) })
            ),
            div({ class: css('_flex _col _gap1') },
              div({ class: css('_h[6px] _rfull _bgmuted/20 _wfull _overflow[hidden]') },
                div({ class: css(`_h[6px] _rfull ${usageColor(pct)}`), style: `width:${pct}%` })
              ),
              div({ class: css('_flex _jcsb _textxs _fgmuted') },
                span({}, `${r.used} ${r.unit}`),
                span({}, `${r.max} ${r.unit}`)
              )
            )
          )
        );
      })
    )
  );
}

